import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { useTelegram } from '../hooks/useTelegram';

interface UserData {
  stars: number;
  lastRewardDate: string | null; // дата последней полученной награды (YYYY-MM-DD)
  rewardsHistory: string[]; // массив дат, когда награды были получены
}

interface UserContextType {
  user: any; // из Telegram
  initData: string;
  webApp: any;
  stars: number;
  rewardsHistory: string[];
  lastRewardDate: string | null;
  addStars: (amount: number) => void;
  claimDailyReward: () => { success: boolean; reward?: number; message?: string };
}

const UserContext = createContext<UserContextType | undefined>(undefined);

const STORAGE_KEY = 'fazercases_user_data';

export const UserProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const { user, initData, webApp } = useTelegram();

  // Инициализация данных из localStorage или по умолчанию
  const [userData, setUserData] = useState<UserData>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      return JSON.parse(saved);
    }
    return {
      stars: 1000, // начальный баланс для теста
      lastRewardDate: null,
      rewardsHistory: [],
    };
  });

  // Сохраняем в localStorage при изменениях
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(userData));
  }, [userData]);

  const addStars = (amount: number) => {
    setUserData(prev => ({ ...prev, stars: prev.stars + amount }));
  };

  const claimDailyReward = () => {
    const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD

    // Если уже получали сегодня
    if (userData.lastRewardDate === today) {
      return { success: false, message: 'Награда уже получена сегодня' };
    }

    // Вычисляем streak (количество дней подряд)
    const lastDate = userData.lastRewardDate ? new Date(userData.lastRewardDate) : null;
    const currentDate = new Date(today);
    let streak = 1;

    if (lastDate) {
      const diffDays = Math.floor((currentDate.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
      if (diffDays === 1) {
        // продолжаем streak
        streak = userData.rewardsHistory.length + 1;
      } else {
        // сброс streak
        streak = 1;
      }
    }

    // Определяем награду: чем больше streak, тем больше награда
    let reward = 50; // базовый бонус
    if (streak >= 30) reward = 500;
    else if (streak >= 20) reward = 300;
    else if (streak >= 10) reward = 200;
    else if (streak >= 5) reward = 100;
    else if (streak >= 2) reward = 75;

    // Обновляем состояние
    setUserData(prev => ({
      ...prev,
      stars: prev.stars + reward,
      lastRewardDate: today,
      rewardsHistory: [...prev.rewardsHistory, today],
    }));

    return { success: true, reward };
  };

  return (
    <UserContext.Provider
      value={{
        user,
        initData,
        webApp,
        stars: userData.stars,
        rewardsHistory: userData.rewardsHistory,
        lastRewardDate: userData.lastRewardDate,
        addStars,
        claimDailyReward,
      }}
    >
      {children}
    </UserContext.Provider>
  );
};

export const useUser = () => {
  const ctx = useContext(UserContext);
  if (!ctx) throw new Error('useUser must be inside UserProvider');
  return ctx;
};
